class Solution:
    def maxFrequency(self, nums, k, numOperations):
        best = 0
        for v in set(nums):
            count = sum(1 for x in nums if v - k <= x <= v + k)
            cnt_equal = sum(1 for x in nums if x == v)
            freq = cnt_equal + min(numOperations, count - cnt_equal)
            if freq > best:
                best = freq
        return best

