var maxFrequency = function(nums, k, numOperations) {
    const sorted = nums.slice().sort((a, b) => a - b);
    const n = sorted.length;
    function lowerBound(x) {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (sorted[mid] < x) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    function upperBound(x) {
        let lo = 0, hi = n;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (sorted[mid] <= x) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    let best = 0;
    for (let i = 0; i < n; i++) {
        const v = sorted[i];
        const lo = lowerBound(v - k);
        const hi = upperBound(v + k) - 1;
        const count = hi - lo + 1;
        const eqLo = lowerBound(v);
        const eqHi = upperBound(v);
        const cntEqual = eqHi - eqLo;
        const freq = cntEqual + Math.min(numOperations, count - cntEqual);
        if (freq > best) best = freq;
    }
    return best;
};
